mapper.update:
UPDATE PROJECT
SET PROJ_STTS = #{projStts}
, PROJ_IPT = 'N'
WHERE PROJ_NO = #{projNo}

mapper.select:
SELECT COUNT(*)
    FROM TASK T
    INNER JOIN TASK_PARTICIPANT TP ON T.TASK_NO = TP.TASK_NO
WHERE T.PROJ_NO = #{projNo}
    AND TP.EMP_ID = #{empId}
    AND (SELECT COUNT(*) FROM TASK_PARTICIPANT TP2 WHERE TP2.TASK_NO = T.TASK_NO) = 1

mapper.delete:
DELETE FROM TASK_PARTICIPANT
    WHERE EMP_ID = #{empId}
AND TASK_NO = #{taskNo}

DELETE FROM PROJECT_PARTICIPANT
    WHERE EMP_ID = #{empId}
AND  PROJ_NO = #{projNo}
